import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { Info } from '@mui/icons-material';
import response from './response.json';

interface TodaySchedule {
  time: string;
  medication: string;
  dose: string;
}

interface RefillDate {
  medication: string;
  nextRefill: string;
}

interface MedicationData {
  todaySchedule: TodaySchedule[];
  adherenceRate: number;
  refillDates: RefillDate[];
}

export default function Widget() {
  const { todaySchedule, adherenceRate, refillDates } = response.data as MedicationData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: 'rgba(255, 255, 255, 0.8)', backdropFilter: 'blur(10px)', borderRadius: 2 }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: response.meta.primaryColor }}>
              Medication Reminder
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Today's Schedule
            </Typography>
            {todaySchedule.map((schedule, index) => (
              <Box key={index} sx={{ display: 'flex', justifyContent: 'space-between', mt: 0.5 }}>
                <Typography variant="body2" fontWeight={500}>
                  {schedule.time}
                </Typography>
                <Typography variant="body2" color="text.secondary">
                  {schedule.medication} - {schedule.dose}
                </Typography>
              </Box>
            ))}
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary">
              Adherence Rate
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: response.meta.accentColor }}>
              {adherenceRate}%
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary">
              Upcoming Refills
            </Typography>
            <Stack direction="row" spacing={1} mt={0.5}>
              {refillDates.map((refill, index) => (
                <Chip
                  key={index}
                  label={`${refill.medication}: ${refill.nextRefill}`}
                  sx={{ fontSize: '10px', bgcolor: response.meta.primaryColor, color: '#fff' }}
                />
              ))}
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
